  ('locality-6e2f88c7-moex-00026', 'locality-6e2f88c7', 'locality-6e2f88c7-moex-114-9b7ab1bb', 'sub-locality-6e2f88c7-03', NULL, 'single_choice', '間接占有人，乃占有媒介關係之一方當事人。下列何者非屬占有媒介關係？', '["附條件買賣關係", "寄託關係", "租賃關係", "抵押權關係"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:46+00:00", "source_pdf_sha1": "60d4037cea76", "answer_pdf_sha1": "42e3c5c0be26", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "315", "s": "0702", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "法制"}'::jsonb, NULL),
